for (var i = 0; i < lines.length; i++) {
    if (lines[i].indexOf('.1.3.6.1.2.1.47.1.1.1.1.5.') !== -1 && lines[i].indexOf('= INTEGER: 3') !== -1) {
        // Extract the SNMPINDEX from the OID
        var oidParts = lines[i].split('.1.3.6.1.2.1.47.1.1.1.1.5.');
        if (oidParts.length > 1) {
            var indexPart = oidParts[1].split(' =')[0];
            targetIndex = indexPart.trim();
            break;
        }
    }
}

// Step 2: If we found a target index, keep all rows containing that index
if (targetIndex !== '') {
    for (var j = 0; j < lines.length; j++) {
        // Check if the line contains the target SNMPINDEX (as a whole number to avoid partial matches)
        if (lines[j].indexOf('.' + targetIndex + ' =') !== -1) {
            result.push(lines[j]);
        }
    }
}

return result.join('\n');

